import { useEffect, useState } from "react";
import axios from "axios";
import CourseDetails from "./CourseDetails";

function App() {
  const [courses, setCourses] = useState([]);
  const [enrolledCourses, setEnrolledCourses] = useState([]);
  const [selectedCourse, setSelectedCourse] = useState(null);
  const [message, setMessage] = useState("");

  const userId = 1;

  useEffect(() => {
    axios.get("http://localhost:5000/courses")
      .then(res => setCourses(res.data));

    axios.get(`http://localhost:5000/enrolled/${userId}`)
      .then(res => setEnrolledCourses(res.data));
  }, []);

  const enrollCourse = async (courseId) => {
    const res = await axios.post("http://localhost:5000/enroll", {
      userId,
      courseId,
    });

    setMessage(res.data.message);

    const updated = await axios.get(`http://localhost:5000/enrolled/${userId}`);
    setEnrolledCourses(updated.data);
  };

  // 👉 Course details page
  if (selectedCourse) {
    return (
      <CourseDetails
        courseId={selectedCourse}
        goBack={() => setSelectedCourse(null)}
      />
    );
  }

  return (
    <div style={{ padding: "20px" }}>
      <h1>LMS System 🚀</h1>

      {message && <p style={{ color: "green" }}>{message}</p>}

      <h2>Courses</h2>

      {courses.map(course => (
        <div key={course.id} style={{ marginBottom: "15px" }}>
          <h3>{course.title}</h3>
          <p>{course.description}</p>

          <button onClick={() => setSelectedCourse(course.id)}>
            View
          </button>

          <button
            onClick={() => enrollCourse(course.id)}
            disabled={enrolledCourses.includes(course.id)}
          >
            {enrolledCourses.includes(course.id) ? "Enrolled" : "Enroll"}
          </button>
        </div>
      ))}

      <h2>My Courses</h2>

      {enrolledCourses.map(id => {
        const course = courses.find(c => c.id === id);
        return <p key={id}>{course?.title}</p>;
      })}
    </div>
  );
}

export default App;
